td>\r\n</tr>\r\n<tr>\r\n<td>2</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-sau-dai-hoc/ths-ky-thuat-y-sinh-287942.html\">Kỹ thuật Y sinh</a></td>\r\n<td>ThS</td>\r\n</tr>\r\n<tr>\r\n<td>3</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-sau-dai-hoc/ths-ky-thuat-vien-thong-287941.html\">Kỹ thuật Viễn thông</a></td>\r\n<td>ThS</td>\r\n</tr>\r\n<tr>\r\n<td>4</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-sau-dai-hoc/ths-ky-thuat-dien-287938.html\">Kỹ thuật Điện</a></td>\r\n<td>ThS</td>\r\n</tr>\r\n<tr>\r\n<td>5</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-sau-dai-hoc/ths-ky-thuat-dieu-khien-va-tu-dong-hoa-287939.html\">Kỹ thuật Điều khiển - Tự động hoá</a></td>\r\n<td>ThS</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div></figure>\r\n</div>', 'Thạc sĩ', '', 'publish', 'open', 'open', '', 'thac-si', '', '', '2025-05-13 02:48:33', '2025-05-13 02:48:33', '', 0, 'http://web-hust.test/?post_type=training&#038;p=169', 0, 'training', '', 0),
