(229, 1, '2025-05-13 03:05:35', '2025-05-13 03:05:35', '<img class=\"\" src=\"https://seee.hust.edu.vn/uploads/seee/tuyen-sinh/2024_12/ts-1.png\" alt=\"CTĐT Trường Điện - Điện tử 2024\" width=\"488\" height=\"363\" />\r\n<p style=\"font-weight: 400;\">CTĐT Trường Điện - Điện tử 2024</p>\r\n\r\n<table>\r\n<tbody>\r\n<tr>\r\n<td>Trường Điện – Điện tử\r\n<b><strong>4</strong></b> ngành đào tạo:\r\n<ul>\r\n 	<li>Kỹ thuật Điện</li>\r\n 	<li>Kỹ thuật Điều khiển và tự động hóa</li>\r\n 	<li>Điện tử - Viễn thông</li>\r\n 	<li>Kỹ thuật Y sinh</li>\r\n</ul>\r\n<b><strong>12</strong></b> chuyên ngành:\r\n<ul>\r\n 	<li>Thiết bị điện</li>\r\n 	<li>Hệ thống điện</li>\r\n 	<li>Điện công nghiệp và dân dụng</li>\r\n 	<li>Tự động hóa công nghiệp</li>\r\n 	<li>Điều khiển tự động</li>\r\n 	<li>Đo lường và tin học công nghiệp</li>\r\n 	<li>Thiết kế vi mạch bán dẫn</li>\r\n 	<li>Kỹ thuật máy tính nhúng</li>\r\n 	<li>Thông tin vô tuyến</li>\r\n 	<li>Mạng thông tin</li>\r\n 	<li>Kỹ thuật Đa phương tiện</li>\r\n 	<li>Kỹ thuật Y sinh</li>\r\n</ul>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<table>\r\n<tbody>\r\n<tr>\r\n<td><b><strong>STT</strong></b></td>\r\n<td><b><strong>Ngành</strong></b></td>\r\n<td><b><strong>Chương</strong></b><b><strong> trình đào tạo</strong></b></td>\r\n<td><b><strong>Mã tuyển sinh\r\n(Ấn vào mã để xem chi tiết)</strong></b></td>\r\n</tr>\r\n<tr>\r\n<td>1</td>\r\n<td rowspan=\"2\"><b><strong><em>Kỹ thuật Điện</em></strong></b></td>\r\n<td>Kỹ thuật điện/Kỹ thuật Điện</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/tuyen-sinh/cac-nganh-chuong-trinh-dao-tao/nganh-ky-thuat-dien-ee1-190979.html\">EE1</a></td>\r\n</tr>\r\n<tr>\r\n<td>2</td>\r\n<td>Kỹ thuật điện/Hệ thống điện và năng lượng tái tạo (CT tiên tiến)</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/tuyen-sinh/dai-hoc/ee-e18-cttt-he-thong-dien-va-nang-luong-tai-tao-317237.html\">EE-E18</a></td>\r\n</tr>\r\n<tr>\r\n<td>3</td>\r\n<td rowspan=\"4\"><b><strong><em>Ngành Kỹ thuật điều khiển &amp; Tự động hóa</em